############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.2.9.115) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "parserNumberWithUnits.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context('Numeric'); $name = randomPerson(); $rate = random(50,65); $speed = NumberWithUnits("$rate mph"); $I = list_random(5,10,15,20,25,35,40,55,65,70,75,80,90,95); $initial = random(100,200); $final = $initial + random(80,250); $solution = ($final - $initial)/$rate; $time = NumberWithUnits("$solution hr");
############################################################ # Body ############################################################
BEGIN_PGML [$name] is driving with an average speed of [`[$speed]`] on Interstate-[$I]. [$name->Subject] [$name->verb('see')] mile marker [$initial] pass by. How long will it take [$name->object] to reach [$name->possessive] destination, which is at mile marker [$final]?
[_]{$time}{16}
END_PGML
############################################################ # End Problem ############################################################
